-- 废弃勿执行：旧 1000 关导入脚本，仅作历史归档。
-- 当前关卡主线使用 database/sql/pve_stages_200.sql。
-- Kesini 轻量关卡 1000 关导入脚本
-- 规则：3 人阵容，敌方战力从 260 递增到 24000，胜利奖励为星穹币。
-- 普通关卡碎片：1-100 N x1，101-200 N x2，201-300 N/R x1，301-400 R x2。
-- 普通关卡碎片：401-500 R/SR x1，501-650 SR x1，651-750 SR x2。
-- 普通关卡碎片：751-850 SR/SSR x1，851-950 SSR x1，951-1000 SSR x2。
-- 里程碑：每 10 关额外通用碎片 x5，每 50 关 x20，每 100 关 x60，按最高档发放。
-- 百关星穹币：第 100 关额外 x100，此后每 100 关递增 x50，计入 points。
-- 可重复导入：同名“星域远征”关卡会先软下线，再插入新关卡。

START TRANSACTION;

-- 确保里程碑奖励能引用默认通用碎片。
SELECT '通用碎片', '全局默认卡片碎片', 0, 0, 0, 0, 1, NOW(6)
WHERE NOT EXISTS (
  SELECT 1
  FROM `drop_item`
  WHERE `drop_type` = 0
    AND `disabled` = 0
    AND `default_fragment` = 1
);

SET @default_fragment_item_id := (
  SELECT `id`
  FROM `drop_item`
  WHERE `drop_type` = 0
    AND `disabled` = 0
    AND `default_fragment` = 1
  ORDER BY `id` ASC
  LIMIT 1
);

-- 确保普通关卡奖励能引用稀有度碎片。
-- 注意：判断用 REPLACE 忽略名称中的空格，避免与历史数据（如 'N 碎片'）重复创建。
SELECT 'N碎片', 'N卡合成碎片', 0, 0, 0, 0, 0, NOW(6)
WHERE NOT EXISTS (
  SELECT 1 FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'N碎片' AND `drop_type` = 0 AND `disabled` = 0
);

SELECT 'R碎片', 'R卡合成碎片', 0, 0, 0, 0, 0, NOW(6)
WHERE NOT EXISTS (
  SELECT 1 FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'R碎片' AND `drop_type` = 0 AND `disabled` = 0
);

SELECT 'SR碎片', 'SR卡合成碎片', 0, 0, 0, 0, 0, NOW(6)
WHERE NOT EXISTS (
  SELECT 1 FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'SR碎片' AND `drop_type` = 0 AND `disabled` = 0
);

SELECT 'SSR碎片', 'SSR卡合成碎片', 0, 0, 0, 0, 0, NOW(6)
WHERE NOT EXISTS (
  SELECT 1 FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'SSR碎片' AND `drop_type` = 0 AND `disabled` = 0
);

SET @n_fragment_item_id := (
  SELECT `id` FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'N碎片' AND `drop_type` = 0 AND `disabled` = 0
  ORDER BY `id` ASC LIMIT 1
);

SET @r_fragment_item_id := (
  SELECT `id` FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'R碎片' AND `drop_type` = 0 AND `disabled` = 0
  ORDER BY `id` ASC LIMIT 1
);

SET @sr_fragment_item_id := (
  SELECT `id` FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'SR碎片' AND `drop_type` = 0 AND `disabled` = 0
  ORDER BY `id` ASC LIMIT 1
);

SET @ssr_fragment_item_id := (
  SELECT `id` FROM `drop_item`
  WHERE REPLACE(`drop_name`, ' ', '') = 'SSR碎片' AND `drop_type` = 0 AND `disabled` = 0
  ORDER BY `id` ASC LIMIT 1
);

UPDATE `pve_stage`
SET `enabled` = 0, `delete_flag` = 1, `updatedAt` = NOW(6)
WHERE `name` LIKE '星域远征 %';

;

COMMIT;

SELECT COUNT(*) AS imported_pve_stages FROM `pve_stage` WHERE `name` LIKE '星域远征 %' AND `delete_flag` = 0;
